UPDATE block SET config = '{"events":[{"date":"Sunday, January 17","time":"7:00 – 11:00 AM","name":"Shuttle Bus 🧳🚌","description":"Shuttle buses will be leaving from the Tin Nghia My company in Go Cong Tay, and heading straight to Lan Rung resort in Phuoc Hai, Vung Tau. We can''t wait to see you there—so please try not to be late! For those who are not from there and need a ride to Lan Rung, we''re more than happy to help arrange transportation. Just let us know!","location":"Nhà Phân Phối VLXD Tín Nghĩa Mỹ, Gò Công Tây, Tiền Giang","maps_url":"https://www.google.com/maps/search/?api=1&query=Nh%C3%A0+Ph%C3%A2n+Ph%E1%BB%91i+VLXD+T%C3%ADn+Ngh%C4%A9a+M%E1%BB%B9","dress_code":""},{"date":"Sunday, January 17","time":"11:00 AM – 1:00 PM","name":"Pre-Wedding Lunch 🥗🍹","description":"After we arrive at the resort, we will check into our rooms and enjoy a delightful lunch together.","location":"Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu","maps_url":"https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort","dress_code":""},{"date":"Sunday, January 17","time":"1:00 – 4:00 PM","name":"Relaxing Time 👟💄","description":"Time to get ready and dress up for the wedding ceremony. If you have a little extra time before things kick off, feel free to take a stroll around the resort and check out all the fun amenities!","location":"Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu","maps_url":"https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort","dress_code":""},{"date":"Sunday, January 17","time":"4:00 PM","name":"Ceremony & Reception 🥳🎈","description":"We''re thrilled to announce that we''re tying the knot! Join us for an evening filled with joy, laughter, and celebration as we share our love with all of you. Enjoy delicious cocktails, a delightful dinner, and refreshing drinks as we kick off this exciting new chapter together!","location":"Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu","maps_url":"https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort","dress_code":"Cocktail Attire"},{"date":"Monday, January 18","time":"7:00 – 9:00 AM","name":"Post-Wedding Breakfast 🥐🥂","description":"We would love to gather with all our guests for a buffet breakfast at the resort the morning after the wedding. It will be a wonderful opportunity for everyone to relax, share stories from the celebration, and enjoy a variety of breakfast options together. We hope you''ll join us for this special moment!","location":"Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu","maps_url":"https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort","dress_code":""},{"date":"Monday, January 18","time":"9:00 – 11:00 AM","name":"Bye Bye Bye 🏖️👋","description":"Feel free to enjoy the resort''s amenities until check-out, whether by the pool, on the beach, or at the spa. Once everyone has checked out, we will gather at the bus for our return to Tien Giang at Tin Nghia My Company. We truly appreciate you being here to celebrate this special destination wedding with us. It''s a day we''ll remember fondly for years to come!","location":"Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu","maps_url":"https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort","dress_code":""}]}', updatedAt = 1775785968973 WHERE id = 'blk_dn_sc4';
UPDATE block SET config = '{"items":[{"q":"When is the RSVP deadline?","a":"We''d love to hear from you! Please let us know if you can make it by August, so we can get an accurate headcount. Thanks a bunch!"},{"q":"What will the weather be like?","a":"During the day, expect beautiful, sunny skies with temperatures around 82–85°F (about 28–29°C)."},{"q":"Is the wedding indoors or outdoors?","a":"Our wedding ceremony will take place outdoors, with vows on the beach and the reception by the pool."},{"q":"What should I wear?","a":"Check out our schedule for the dress code details. Just a little tip: the coastal breeze can make things a bit chilly at night, so it''s a great idea to pack a light sweater or wrap to keep cozy during those beautiful evenings."},{"q":"What kind of shoes should/shouldn''t I wear?","a":"We recommend wearing comfortable shoes or sandals for the vow ceremony, as it will take place on the sand. For the reception, feel free to wear your favorite stylish shoes — whether elegant heels or trendy flats, choose something that makes you feel great while allowing you to dance and celebrate!"},{"q":"Is it okay to take pictures during the wedding?","a":"We would love for you to take and share photos throughout the celebration! For the vow ceremony, though, we invite you to be fully present with us and kindly ask that all devices be put away."},{"q":"Can I bring a date?","a":"Please check your invite for your +1!"},{"q":"Are kids welcome?","a":"We absolutely love your little ones, but we kindly ask for a kid-free ceremony and reception. Kids are totally welcome at the pre-wedding lunch and post-wedding breakfast — just let us know in advance so we can accommodate everyone comfortably!"},{"q":"Will the reception be live streamed?","a":"We''re excited to share that we have a talented local streamer from the bride''s side who will be capturing all the unforgettable moments throughout the event — Cậu tư 😜"},{"q":"How will food and drinks be served?","a":"We have a cocktail bar where you can enjoy tasty desserts and tropical cocktails before the ceremony starts. After that, get ready for a buffet meal at the reception that''ll have something for everyone!"},{"q":"What if I have a dietary restriction?","a":"Please take a moment to answer the dietary question in your RSVP, or feel free to reach out to us directly. We want to make sure you have the best possible experience!"},{"q":"Whom should I contact with questions?","a":"For assistance, please reach out to Dannis or Naomi via their phone numbers or social media accounts."}]}', updatedAt = 1775785968973 WHERE id = 'blk_dn_f4';
UPDATE block SET config = '{"columns":"3","cardStyle":"card","tidbitsTitle":"Tidbits","tidbits":[{"q":"What''s your favorite activity together?","a":"We love to seek out new restaurants to explore, especially those featuring seafood delights or exciting new dishes to try."},{"q":"Where are you going for your honeymoon?","a":"To eat food"},{"q":"What''s the best meal you''ve eaten together?","a":"All of them"},{"q":"What''s the most memorable trip you''ve taken together?","a":"Eating food in Vietnam"},{"q":"We''re on the same page about","a":"Food"},{"q":"A life goal of ours","a":"Try all the food across the world"},{"q":"The dorkiest thing about us is","a":"When we''re not exploring new cuisines or enjoying meals, you''ll find us immersed in playing video games together. We love the thrill of conquering new worlds side by side!"},{"q":"A social cause we care about","a":"We should never eat dogs and cats"},{"q":"We are regulars at","a":"Our dinner table"},{"q":"Teach us something about","a":"Food"},{"q":"We take pride in","a":"We take immense pride in raising our beloved pets, Winston and Wendy. Winston is the epitome of a gentleman—well-behaved and polite in every way. But then there''s Wendy... she''s a whole different story!"}]}', updatedAt = 1775785968973 WHERE id = 'blk_dn_s5';
UPDATE block SET config = '{"name":"Lan Rung Beach Resort","description":"We love Lan Rung Beach Resort for its picturesque location right on the beach — perfect for a romantic beach wedding getaway. The rooms are clean and comfortable, the staff are friendly and accommodating, and the affordable price range makes it a great option for all guests.","room_note":"Rooms have not been released for the event dates yet. Check back soon for booking details.","map_url":"https://www.google.com/maps/search/Lan+Rung+Beach+Resort+Phuoc+Hai+Vietnam"}', updatedAt = 1775785968973 WHERE id = 'blk_dn_a5';
